parameters.inputSchema:
{
  "type": "object",
  "properties": {
    "incremental_context": {
      "type": "object",
      "description": "Combined incremental clinical context. Empty object if no data.",
      "properties": {
        "incremental_summary": {
          "type": "object",
          "properties": {
            "patient_profile": {
              "type": "object",
              "properties": {
                "age": {
                  "type": "string"
                },
                "sex": {
                  "type": "string"
                },
                "relevant_comorbidities": {
                  "type": "array",
                  "items": {
                    "type": "string"
                  }
                },
                "risk_factors": {
                  "type": "array",
                  "items": {
                    "type": "string"
                  }
                }
              }
            },
            "subjective_symptoms": {
              "type": "array",
              "items": {
                "type": "string"
              }
            },
            "objective_findings": {
              "type": "array",
              "items": {
                "type": "string"
              }
            },
            "clinical_patterns": {
              "type": "array",
              "items": {
                "type": "string"
              }
            },
            "clinical_problems": {
              "type": "object",
              "properties": {
                "primary_problem": {
                  "type": "string"
                },
                "secondary_problems": {
                  "type": "array",
                  "items": {
                    "type": "string"
                  }
                },
                "emerging_problems": {
                  "type": "array",
                  "items": {
                    "type": "string"
                  }
                },
                "resolved_problems": {
                  "type": "array",
                  "items": {
                    "type": "string"
                  }
                }
              }
            },
            "clinical_red_flags": {
              "type": "array",
              "items": {
                "type": "string"
              }
            },
            "timeline_of_events": {
              "type": "array",
              "items": {
                "type": "string"
              }
            }
          }
        },
        "clinical_reasoning_state": {
          "type": "object",
          "properties": {
            "diagnostic_anchor": {
              "type": "string"
            },
            "key_clinical_abnormalities": {
              "type": "array",
              "items": {
                "type": "string"
              }
            },
            "suspected_diagnostic_directions": {
              "type": "array",
              "items": {
                "type": "string"
              }
            },
            "severity_assessment": {
              "type": "string"
            },
            "unresolved_conflicts": {
              "type": "array",
              "items": {
                "type": "string"
              }
            },
            "information_gaps": {
              "type": "array",
              "items": {
                "type": "string"
              }
            }
          }
        }
      }
    },
    "error": {
      "type": "string",
      "description": "Error message when no valid input is available"
    }
  },
  "required": [
    "incremental_context"
  ]
}

{
  "type": "object",
  "properties": {
    "differential_diagnosis": {
      "type": "array",
      "description": "Ranked list of plausible differential diagnoses generated from the incremental clinical context.",
      "items": {
        "type": "object",
        "properties": {
          "rank": {
            "type": "integer",
            "description": "Rank of the diagnosis based on likelihood. Rank 1 represents the most likely diagnosis."
          },
          "full_name": {
            "type": "string",
            "description": "Complete clinical or medical name of the condition."
          },
          "common_name": {
            "type": "string",
            "description": "Common or everyday name used to describe the condition."
          },
          "confidence": {
            "type": "string",
            "description": "Confidence percentage representing the likelihood of this diagnosis based on the available clinical evidence. Format must be a numeric percentage such as '95%', '72%', or '40%'."
          },
          "supporting_evidence": {
            "type": "array",
            "description": "Findings from the incremental clinical context that support this diagnosis, such as symptoms, objective findings, clinical patterns, or key abnormalities.",
            "items": {
              "type": "string"
            }
          },
          "conflicting_evidence": {
            "type": "array",
            "description": "Findings from the incremental clinical context that weaken or are inconsistent with this diagnosis.",
            "items": {
              "type": "string"
            }
          },
          "reason": {
            "type": "string",
            "description": "Explanation for why this diagnosis is considered, based on supporting and conflicting evidence, in not more than 100 words."
          },
          "description": {
            "type": "string",
            "description": "Brief introduction to the disease or condition in not more than 50 words."
          },
          "emergency": {
            "type": "string",
            "description": "Level of urgency or clinical severity of the condition. Must be one of: 'low', 'medium', 'high', 'very high'."
          }
        },
        "required": [
          "rank",
          "full_name",
          "common_name",
          "confidence",
          "supporting_evidence",
          "conflicting_evidence",
          "reason",
          "description",
          "emergency"
        ]
      }
    },
    "error": {
      "type": "string",
      "description": "Error message when no clinical information is available to generate differential diagnosis."
    }
  },
  "required": [
    "differential_diagnosis"
  ]
}
